// And groups predicates with the AND operator between them.
func And(predicates ...predicate.OCRTask) predicate.OCRTask {
	return predicate.OCRTask(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.OCRTask) predicate.OCRTask {
	return predicate.OCRTask(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.OCRTask) predicate.OCRTask {
	return predicate.OCRTask(sql.NotPredicates(p))
}
